queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?act_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:acts_comedy_shows_id ?cg . ?child a :Acts ; p:act_id ?cg . ?l p:comedy_show_id ?pg . ?parent a :Comedy_Shows ; p:comedy_show_id ?pg . } GROUP BY ?child }
  ?child p:act_name ?act_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Comedy_Shows } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?act_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:acts_comedy_shows_id ?cg . ?child a :Acts ; p:act_id ?cg . ?l p:comedy_show_id ?pg . ?parent a :Comedy_Shows ; p:comedy_show_id ?pg . } GROUP BY ?child }
  ?child p:act_name ?act_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Comedy_Shows } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?show_title ?act_name WHERE {
  ?comedy_shows_acts a :Comedy_Shows_Acts .
  ?comedy_shows a :Comedy_Shows .
  ?comedy_shows_acts p:hasComedy_Shows ?comedy_shows .
  ?acts a :Acts .
  ?comedy_shows_acts p:hasActs ?acts .
  ?comedy_shows p:show_title ?show_title .
  ?acts p:act_name ?act_name .
} }
}
